import os
import hashlib
import hmac
from datetime import datetime, timedelta
from functools import wraps
from flask import Flask, session, request, redirect, url_for, jsonify

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', os.urandom(32))
app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(days=7)

users_db = {}
sessions_db = {}

def hash_password(password, salt=None):
    if salt is None:
        salt = os.urandom(32)
    pwd_hash = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt, 100000)
    return salt + pwd_hash

def verify_password(stored_password, provided_password):
    salt = stored_password[:32]
    stored_hash = stored_password[32:]
    pwd_hash = hashlib.pbkdf2_hmac('sha256', provided_password.encode('utf-8'), salt, 100000)
    return hmac.compare_digest(stored_hash, pwd_hash)

def generate_session_token():
    return hashlib.sha256(os.urandom(32)).hexdigest()

def create_session(user_id):
    token = generate_session_token()
    sessions_db[token] = {
        'user_id': user_id,
        'created_at': datetime.utcnow(),
        'expires_at': datetime.utcnow() + timedelta(days=7)
    }
    return token

def get_session(token):
    if token in sessions_db:
        session_data = sessions_db[token]
        if datetime.utcnow() < session_data['expires_at']:
            return session_data
        else:
            del sessions_db[token]
    return None

def delete_session(token):
    if token in sessions_db:
        del sessions_db[token]

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = session.get('session_token')
        if not token:
            return jsonify({'error': 'Not authenticated'}), 401
        
        session_data = get_session(token)
        if not session_data:
            session.pop('session_token', None)
            return jsonify({'error': 'Session expired'}), 401
        
        request.user_id = session_data['user_id']
        return f(*args, **kwargs)
    return decorated_function

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    username = data.get('username', '').strip()
    password = data.get('password', '')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    if len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400
    
    if username in users_db:
        return jsonify({'error': 'Username already exists'}), 400
    
    users_db[username] = {
        'password': hash_password(password),
        'created_at': datetime.utcnow()
    }
    
    return jsonify({'message': 'User registered successfully'}), 201

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username', '').strip()
    password = data.get('password', '')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    user = users_db.get(username)
    if not user or not verify_password(user['password'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    token = create_session(username)
    session['session_token'] = token
    session.permanent = True
    
    return jsonify({'message': 'Logged in successfully', 'username': username}), 200

@app.route('/logout', methods=['POST'])
@login_required
def logout():
    token = session.get('session_token')
    if token:
        delete_session(token)
        session.pop('session_token', None)
    
    return jsonify({'message': 'Logged out successfully'}), 200

@app.route('/profile', methods=['GET'])
@login_required
def profile():
    username = request.user_id
    user = users_db.get(username)
    
    return jsonify({
        'username': username,
        'created_at': user['created_at'].isoformat()
    }), 200

@app.route('/sessions', methods=['GET'])
@login_required
def list_sessions():
    username = request.user_id
    user_sessions = []
    
    for token, session_data in sessions_db.items():
        if session_data['user_id'] == username:
            user_sessions.append({
                'created_at': session_data['created_at'].isoformat(),
                'expires_at': session_data['expires_at'].isoformat(),
                'is_current': token == session.get('session_token')
            })
    
    return jsonify({'sessions': user_sessions}), 200

if __name__ == '__main__':
    app.run(debug=False)